//! External-circuit compatibility smoke test (Tier A3).
//!
//! Runs `halo2_solana_verifier::verify` against a proof generated by the
//! snark-verifier-sdk-shape StandardPlonk circuit (1 instance column,
//! gate references `Expression::Instance`). Reports pass/fail.

use external_sp_circuit::generate_test_vector;
use halo2_solana_verifier::field::fr_to_bytes_be;

fn main() -> Result<(), anyhow::Error> {
    let seed = [7u8; 32];
    let k = 4;

    eprintln!("[1/4] generating KZG params (k={k}) + external StandardPlonk witness…");
    let v = generate_test_vector(k, seed)?;

    eprintln!(
        "[2/4] outputs:  vk={} B   proof={} B   instance={}",
        v.vk_bytes.len(), v.proof_bytes.len(), display_fr(&v.instance_value),
    );

    eprintln!("[3/4] running halo2_solana_verifier::verify…");
    let public_inputs: Vec<[u8; 32]> = vec![fr_to_bytes_be(&ark_fr(&v.instance_value))];
    let result = halo2_solana_verifier::verify(
        &v.vk_bytes, &v.proof_bytes, &public_inputs, &v.kzg_vk,
    );
    eprintln!("[4/4] verifier returned: {result:?}");

    match &result {
        Ok(true)  => eprintln!("✓ external StandardPlonk proof verified end-to-end"),
        Ok(false) => return Err(anyhow::anyhow!("verifier returned Ok(false) — soundness gap")),
        Err(e)    => return Err(anyhow::anyhow!("verifier error: {e}")),
    }

    // ── Soundness sanity: a tampered proof must reject ──
    eprintln!("[5/?] running negative test — flipping one byte of the proof bytes…");
    let mut tampered = v.proof_bytes.clone();
    let mid = tampered.len() / 2;
    tampered[mid] ^= 0x01;
    let neg_result = halo2_solana_verifier::verify(
        &v.vk_bytes, &tampered, &public_inputs, &v.kzg_vk,
    );
    match neg_result {
        Ok(false) | Err(_) => {
            eprintln!("       ✓ verifier rejected tampered proof: {neg_result:?}");
        }
        Ok(true) => {
            return Err(anyhow::anyhow!(
                "SOUNDNESS BUG: verifier accepted a tampered proof"
            ));
        }
    }

    // ── Substituted-instance test: changing public input must reject ──
    eprintln!("[6/?] running negative test — flipping public input value…");
    let mut bad_pi = ark_fr(&v.instance_value);
    bad_pi += ark_bn254::Fr::from(1u64);
    let bad_pis: Vec<[u8; 32]> = vec![fr_to_bytes_be(&bad_pi)];
    let pi_result = halo2_solana_verifier::verify(
        &v.vk_bytes, &v.proof_bytes, &bad_pis, &v.kzg_vk,
    );
    match pi_result {
        Ok(false) | Err(_) => {
            eprintln!("       ✓ verifier rejected wrong public input: {pi_result:?}");
        }
        Ok(true) => {
            return Err(anyhow::anyhow!(
                "SOUNDNESS BUG: verifier accepted a proof under wrong public input"
            ));
        }
    }

    eprintln!();
    eprintln!("Tier A3 compat test complete: external StandardPlonk circuit passes");
    eprintln!("positive verify + 2 negative-reject (proof tamper, PI substitution).");
    Ok(())
}

fn ark_fr(t: &halo2curves::bn256::Fr) -> ark_bn254::Fr {
    use halo2curves::ff::PrimeField;
    let mut le = t.to_repr();
    le.as_mut().reverse();
    let mut be = [0u8; 32];
    be.copy_from_slice(le.as_ref());
    halo2_solana_verifier::field::fr_from_bytes_be(&be)
        .expect("canonical Fr")
}

fn display_fr(t: &halo2curves::bn256::Fr) -> String {
    use halo2curves::ff::PrimeField;
    let le = t.to_repr();
    let mut be = le;
    be.as_mut().reverse();
    let mut s = String::with_capacity(66);
    s.push_str("0x");
    for b in be.as_ref() { s.push_str(&format!("{b:02x}")); }
    s
}
